{
  "title": "उचित उद्धरण",
  "group": "उद्धरण 1",
  "options": [
    {"text": "दोनों एक ही तरह से काम करते हैं"},
    {"text": "डबल उद्धरण आवश्यक हैं"},
    {"text": "एकल उद्धरण आवश्यक हैं"},
    {"text": "सिंटैक्स त्रुटि: अवैध उपयोगकर्ता लीटरल"},
    {"text": "सभी नामों को छोटे अक्षरों में होना चाहिए"}
  ],
  "questionProse": [
    "केस-सेंसिटिव कॉलम नामों के लिए कौन सा सही है?"
  ],
  "explanationProse": [
    "PostgreSQL में:\n    - डबल उद्धरण (`\"`) आइडेंटिफायर्स (टेबल नाम, कॉलम नाम) के लिए होते हैं\n    - एकल उद्धरण (`'`) स्ट्रिंग लीटरल के लिए होते हैं\n\n    उपयोग के नियम:\n    - नामों में मिश्रित मामला या स्पेस टालें\n    - आइडेंटिफायर्स के लिए स्नेक_केस का उपयोग करें\n    - केवल अत्यंत आवश्यकता पर उद्धृत आइडेंटिफायर्स का उपयोग करें"
  ]
}
